css:
.loader {
  display: grid;
  gap: 7px;
  width: 84px;
  color: #6366f1;
}
.loader b {
  display: block;
  height: 10px;
  border-radius: 999px;
  background: currentColor;
  animation: stack 1s ease-in-out infinite;
}
.loader b:nth-child(2) { animation-delay: 0.16s; }
.loader b:nth-child(3) { animation-delay: 0.32s; }
@keyframes stack {
  0%, 100% { transform: scaleX(0.38); opacity: 0.38; }
  50% { transform: scaleX(1); opacity: 1; }
}
